


/* ── RENDER ── */
const el = id => document.getElementById(id);
function svg(){return typeof SERVICES !== 'undefined' ? SERVICES.map(s=>`<div class="col-lg-4 col-md-6"><div class="svc-card"><img src="${s.img}" alt="${s.t}"><div class="num-eyebrow mt-3">${s.n} / 06</div><h3 class="text-white">${s.t}</h3><p style="color:var(--slate-300);font-size:14px;line-height:1.6">${s.b}</p><div class="d-flex flex-wrap gap-1">${s.tags.map(t=>`<span class="tag">${t}</span>`).join('')}</div></div></div>`).join('') : ''}
if(typeof SERVICES !== 'undefined' && el('svcGrid')) el('svcGrid').innerHTML = svg();
if(typeof INDUSTRIES !== 'undefined' && el('indGrid')) el('indGrid').innerHTML = INDUSTRIES.map(i=>`<div class="col-lg-3 col-md-4 col-6"><div class="industry"><img src="${i.img}" alt="${i.name}"><div class="ov"><div class="num-eyebrow">${i.n}</div><h4>${i.name}</h4></div></div></div>`).join('');
if(typeof WHY !== 'undefined' && el('whyPoints')) el('whyPoints').innerHTML = WHY.map(p=>`<div class="row g-3 py-3 border-top" style="border-color:rgba(255,255,255,.1)!important"><div class="col-2 num-eyebrow pt-1">${p.n}</div><div class="col-10"><h4 class="ff-display text-white mb-1" style="font-size:18px">${p.t}</h4><p class="mb-0" style="color:rgba(255,255,255,.65);font-size:14px">${p.b}</p></div></div>`).join('');
function getProjectData(card){
  const img = card.querySelector('img');
  const cat = card.querySelector('.cat')?.textContent.trim().toLowerCase() || '';
  const name = card.querySelector('.nm')?.textContent.trim() || '';
  const ovDivs = card.querySelectorAll('.ov > div');
  const meta = ovDivs[2]?.textContent.trim() || '';
  return { card, img, cat, name, meta };
}
function getVisibleProjectItems(){
  return Array.from(document.querySelectorAll('#projGrid .proj'))
    .filter(card=> !card.parentElement?.classList.contains('d-none'))
    .map(getProjectData);
}
function renderProj(f){
  if(!el('projGrid')) return;
  const cards = Array.from(el('projGrid').querySelectorAll('.proj'));
  cards.forEach((card, idx) => {
    const data = getProjectData(card);
    const visible = f === 'all' || data.cat === f;
    card.parentElement?.classList.toggle('d-none', !visible);
    card.dataset.idx = idx;
  });
}

// LIGHTBOX
function _ensureLightbox(){ if(document.getElementById('projLightbox')) return;
  const style = document.createElement('style'); style.id='projLightboxStyle'; style.textContent = `#projLightbox{position:fixed;inset:0;display:flex;align-items:center;justify-content:center;background:rgba(0,0,0,.85);z-index:9999;opacity:0;pointer-events:none;transition:opacity .2s}#projLightbox.open{opacity:1;pointer-events:auto}#projLightbox img{max-width:92%;max-height:80%;box-shadow:0 8px 30px rgba(0,0,0,.6)}#projLightbox .lb-caption{color:#fff;margin-top:12px;text-align:center;font-size:14px}#projLightbox .lb-close,#projLightbox .lb-prev,#projLightbox .lb-next{position:fixed;background:transparent;border:0;color:#fff;font-size:28px;padding:12px;cursor:pointer}#projLightbox .lb-close{top:18px;right:22px}#projLightbox .lb-prev{left:18px;top:50%;transform:translateY(-50%)}#projLightbox .lb-next{right:18px;top:50%;transform:translateY(-50%)}`; document.head.appendChild(style);
  const lb = document.createElement('div'); lb.id='projLightbox'; lb.innerHTML = `<button class="lb-close" aria-label="Close">×</button><button class="lb-prev" aria-label="Previous">‹</button><div class="lb-inner"><img id="lb-img" src="" alt=""><div class="lb-caption" id="lb-caption"></div></div><button class="lb-next" aria-label="Next">›</button>`; document.body.appendChild(lb);
  lb.addEventListener('click',e=>{ if(e.target.id==='projLightbox' || e.target.classList.contains('lb-close')) closeLightbox(); });
  lb.querySelector('.lb-prev').addEventListener('click',e=>{ e.stopPropagation(); const count = getVisibleProjectItems().length; showLightbox((lb._idx-1+count)%count); });
  lb.querySelector('.lb-next').addEventListener('click',e=>{ e.stopPropagation(); const count = getVisibleProjectItems().length; showLightbox((lb._idx+1)%count); });
  document.addEventListener('keydown',e=>{ const elb=document.getElementById('projLightbox'); if(!elb || !elb.classList.contains('open')) return; if(e.key==='Escape') closeLightbox(); if(e.key==='ArrowLeft') elb.querySelector('.lb-prev').click(); if(e.key==='ArrowRight') elb.querySelector('.lb-next').click(); });
}
function showLightbox(idx){
  _ensureLightbox();
  const lb=document.getElementById('projLightbox');
  if(!lb) return;
  const items = getVisibleProjectItems();
  if(!items.length) return;
  idx = ((idx % items.length) + items.length) % items.length;
  const p = items[idx];
  if(!p || !p.img) return;
  const img = lb.querySelector('#lb-img');
  const imgSrc = p.img.currentSrc || p.img.src || '';
  if(!imgSrc) return;
  img.src = imgSrc;
  img.alt = p.name;
  lb._idx = idx;
  lb.querySelector('#lb-caption').textContent = p.name + (p.meta ? ' · '+p.meta : '');
  lb.classList.add('open');
}
function closeLightbox(){ const lb=document.getElementById('projLightbox'); if(lb) lb.classList.remove('open'); }

function attachGalleryEvents(){
  const grid = el('projGrid');
  if(!grid) return false;
  if(grid._galleryEventsAttached) return true;
  grid.addEventListener('click', e=>{
    const pEl = e.target.closest('.proj');
    if(!pEl) return;
    _ensureLightbox();
    const visible = Array.from(grid.querySelectorAll('.proj')).filter(card=> !card.parentElement?.classList.contains('d-none'));
    const idx = visible.indexOf(pEl);
    if(idx === -1) return;
    showLightbox(idx);
  });
  grid._galleryEventsAttached = true;
  return true;
}

function attachFilterEvents(){
  const filtersContainer = el('filters');
  if(!filtersContainer) return false;
  if(filtersContainer._filterEventsAttached) return true;
  filtersContainer.addEventListener('click', function(e){
    const btn = e.target.closest('.filter-btn');
    if(!btn) return;
    e.preventDefault();
    document.querySelectorAll('.filter-btn').forEach(x=>x.classList.remove('active'));
    btn.classList.add('active');
    renderProj(btn.dataset.f);
  });
  filtersContainer._filterEventsAttached = true;
  return true;
}

function initProjectGallery(){
  const galleryReady = attachGalleryEvents();
  const filtersReady = attachFilterEvents();
  if(galleryReady && filtersReady){
    renderProj('all');
    return true;
  }
  return false;
}

function whenReady(fn){
  if(document.readyState === 'loading'){
    document.addEventListener('DOMContentLoaded', fn);
  } else {
    fn();
  }
}
whenReady(initProjectGallery);
if(typeof AREAS !== 'undefined' && el('areaList')) el('areaList').innerHTML = AREAS.map(a=>`<div class="col-md-6"><a href="#area-${a.slug}" class="area-row"><div><div class="an">${a.name}</div><div class="am">${a.note}</div></div><span class="text-slate">→</span></a></div>`).join('');
if(typeof AREAS !== 'undefined' && el('locationPages')) el('locationPages').innerHTML = AREAS.map(a=>`<article id="area-${a.slug}" class="location"><div class="container"><div class="row g-5 align-items-center"><div class="col-lg-6 position-relative"><img src="${a.img}" alt="${a.name}"><div class="position-absolute top-0 start-0 m-3 px-3 py-2 ff-mono text-uppercase" style="background:var(--navy-900);color:#fff;font-size:10px;letter-spacing:.16em">${a.name} · Colorado</div></div><div class="col-lg-6"><div class="eyebrow">Service Area · ${a.note}</div><h2 class="mt-2">${a.h2}</h2><p class="text-slate mt-3" style="font-size:15px;line-height:1.6">${a.body}</p><div class="ff-mono text-uppercase mt-4 mb-2" style="font-size:11px;letter-spacing:.14em;color:var(--slate-500)">Services available in ${a.name}</div><ul><li>Commercial Concrete</li><li>Asphalt Paving &amp; Repair</li><li>Commercial Masonry</li><li>Snow Melt Systems</li><li>HOA &amp; Property Management</li><li>Concrete Finishes</li></ul><div class="d-flex gap-2 mt-3 flex-wrap"><a href="#contact" class="btn btn-navy btn-arrow">Request a Quote in ${a.name}</a><a href="tel:+13034793181" class="btn btn-outline-navy">Call (303) 479-3181</a></div></div></div></div></article>`).join('');
if(typeof AREAS !== 'undefined' && el('areaMenu')) el('areaMenu').innerHTML = AREAS.map(a=>`<li><a class="dropdown-item" href="#area-${a.slug}">${a.name}</a></li>`).join('');
if(typeof AREAS !== 'undefined' && el('footAreas1')) el('footAreas1').innerHTML = AREAS.slice(0,7).map(a=>`<a class="footer-link" href="#area-${a.slug}">${a.name}</a>`).join('');
if(typeof AREAS !== 'undefined' && el('footAreas2')) el('footAreas2').innerHTML = AREAS.slice(7).map(a=>`<a class="footer-link" href="#area-${a.slug}">${a.name}</a>`).join('');

/* Hero slides */
const HERO=["data:image/jpeg;base64,","data:image/jpeg;base64,","data:image/jpeg;base64,","data:image/jpeg;base64,","data:image/jpeg;base64,"];
el('heroSlides').innerHTML = HERO.map((s,i)=>`<div class="hero-slide ${i==0?'active':''}" style="background-image:url(${s})"></div>`).join('');
let hi=0; setInterval(()=>{const sl=document.querySelectorAll('.hero-slide');sl[hi].classList.remove('active');hi=(hi+1)%sl.length;sl[hi].classList.add('active')},6500);

/* Reviews rotation */
let reviews = [];
if(el('revItems')){
  reviews = Array.from(el('revItems').querySelectorAll('.review-item')).map(item=>({
    title: item.querySelector('.title')?.textContent.trim() || '',
    q: item.querySelector('.quote')?.textContent.trim() || '',
    n: item.querySelector('.name')?.textContent.trim() || '',
    r: item.querySelector('.role')?.textContent.trim() || ''
  }));
} else if(typeof TESTS !== 'undefined'){
  reviews = TESTS;
}
let ri=0;
function renderRev(){
  const t = reviews[ri]; if(!t) return;
  el('revTitle').textContent = t.title;
  el('revQuote').textContent = '"'+t.q+'"';
  el('revName').textContent = t.n;
  el('revRole').textContent = t.r;
  if(el('revDots')) el('revDots').innerHTML = reviews.map((_,i)=>`<button data-i="${i}" style="width:28px;height:2px;border:0;background:${i==ri?'#fff':'rgba(255,255,255,.2)'}"></button>`).join('');
  document.querySelectorAll('#revDots button').forEach(b=>b.onclick=()=>{ri=+b.dataset.i;renderRev()});
}
renderRev();
setInterval(()=>{ if(reviews.length){ ri=(ri+1)%reviews.length; renderRev(); } },8000);

/* Nav scroll */
window.addEventListener('scroll',()=>{document.getElementById('mainNav').classList.toggle('scrolled',window.scrollY>40)});

/* Form */
if(el('quoteForm')){
  el('quoteForm').onsubmit=e=>{e.preventDefault();el('quoteForm').classList.add('d-none');if(el('formSuccess')) el('formSuccess').classList.remove('d-none');};
}

/* Reveal on scroll */
const io=new IntersectionObserver(es=>es.forEach(e=>{if(e.isIntersecting){e.target.classList.add('in');io.unobserve(e.target)}}),{threshold:.08,rootMargin:'0px 0px -60px 0px'});
document.querySelectorAll('.reveal').forEach(r=>io.observe(r));

/* Close mobile nav on link click */
document.querySelectorAll('#navMenu .nav-link:not(.dropdown-toggle), #navMenu .dropdown-item').forEach(a=>a.addEventListener('click',()=>{const c=document.getElementById('navMenu');if(c.classList.contains('show'))new bootstrap.Collapse(c).hide()}));
